    pow1 = pow(I1x,2 );
    pow2 = pow(I2x,2 );
    pow3 = pow(l1,2 );
    pow4 = pow(l2,2 );
    pow5 = pow(Ms,2 );
    pow6 = pow(Mt,2 );
    pow7 = pow(Mp,2 );
    pow8 = pow(l2,4 );
    pow9 = pow(l1,4 );
    powI0 = pow(Ms,3 );
    pow11 = pow(Mt,3 );
