double low_pass_filter (double old_data, double raw_data, double dt, double RC) {
	
	/*Need to tune the parameters*/
	
	/*double tf = 0.01;
	double ts = 0.01;*/
	double alpha;
	double filtered_data;
	
	alpha = dt/(dt+RC);
	//printf("%f\n",alpha);
	
	filtered_data = alpha*old_data+(1-alpha)*raw_data;
	
	return filtered_data;
	
}

double kalman_filter(double raw_data, double old_data, double * p, double *q, double *r, double * kGain) {
	
	*p = *p + *q;
	*kGain = *p/(*p+*r);
	raw_data = old_data+ *kGain * (raw_data-old_data);
	*p = (1-*kGain) * *p;
	
	return raw_data;
	
}

